  1→/**
  2→ * Knowledge Base Validation Tests - SKF Module
  3→ *
  4→ * Tests skf-knowledge-index.csv parsing, fragment existence, tag selection,
  5→ * and cross-fragment link references.
  6→ *
  7→ * Usage: node test/test-knowledge-base.js
  8→ */
  9→
 10→const fs = require('node:fs');
 11→const path = require('node:path');
 12→const { parse } = require('csv-parse/sync');
 13→
 14→// ANSI colors
 15→const colors = {
 16→  reset: '\u001B[0m',
 17→  green: '\u001B[32m',
 18→  red: '\u001B[31m',
 19→  yellow: '\u001B[33m',
 20→  cyan: '\u001B[36m',
 21→  dim: '\u001B[2m',
 22→};
 23→
 24→let passed = 0;
 25→let failed = 0;
 26→let warned = 0;
 27→
 28→function assert(condition, testName, errorMessage = '') {
 29→  if (condition) {
 30→    console.log(`${colors.green}✓${colors.reset} ${testName}`);
 31→    passed++;
 32→  } else {
 33→    console.log(`${colors.red}✗${colors.reset} ${testName}`);
 34→    if (errorMessage) {
 35→      console.log(`  ${colors.dim}${errorMessage}${colors.reset}`);
 36→    }
 37→    failed++;
 38→  }
 39→}
 40→
 41→function warn(message) {
 42→  console.log(`${colors.yellow}•${colors.reset} ${message}`);
 43→  warned++;
 44→}
 45→
 46→function parseTags(tagString) {
 47→  if (!tagString) return [];
 48→  return tagString
 49→    .split(',')
 50→    .map((tag) => tag.trim())
 51→    .filter(Boolean);
 52→}
 53→
 54→function isExternalLink(href) {
 55→  return href.startsWith('http://') || href.startsWith('https://');
 56→}
 57→
 58→function resolveFragmentLink(baseDir, href) {
 59→  if (href.startsWith('knowledge/')) {
 60→    return path.join(baseDir, href);
 61→  }
 62→  if (href.startsWith('./') || href.startsWith('../')) {
 63→    return path.join(baseDir, href);
 64→  }
 65→  // If only a filename is provided, assume knowledge dir
 66→  if (href.endsWith('.md') && !href.includes('/')) {
 67→    return path.join(baseDir, 'knowledge', href);
 68→  }
 69→  return null;
 70→}
 71→
 72→function runTests() {
 73→  console.log(`${colors.cyan}========================================`);
 74→  console.log('SKF Knowledge Base Tests');
 75→  console.log(`========================================${colors.reset}\n`);
 76→
 77→  const projectRoot = path.join(__dirname, '..');
 78→  const kbRoot = path.join(projectRoot, 'src', 'knowledge');
 79→  const indexPath = path.join(kbRoot, 'skf-knowledge-index.csv');
 80→
 81→  // ============================================================
 82→  // Test 1: Parse CSV and validate structure
 83→  // ============================================================
 84→  console.log(`${colors.yellow}Test Suite 1: CSV Structure${colors.reset}\n`);
 85→
 86→  let records = [];
 87→  try {
 88→    const csv = fs.readFileSync(indexPath, 'utf8');
 89→    records = parse(csv, { columns: true, skip_empty_lines: true });
 90→
 91→    assert(records.length === 13, 'skf-knowledge-index.csv has 13 fragment records', `Found ${records.length}`);
 92→
 93→    const requiredFields = ['id', 'name', 'description', 'tags', 'tier', 'fragment_file'];
 94→    const missingFields = requiredFields.filter((field) => !Object.prototype.hasOwnProperty.call(records[0] || {}, field));
 95→    assert(missingFields.length === 0, 'skf-knowledge-index.csv has required columns', missingFields.join(', '));
 96→
 97→    // Validate tier values
 98→    const validTiers = new Set(['core', 'extended', 'specialized']);
 99→    const invalidTiers = records.filter((r) => !validTiers.has(r.tier));
100→    assert(
101→      invalidTiers.length === 0,
102→      'All fragments have valid tier values (core/extended/specialized)',
103→      invalidTiers.map((r) => `${r.id}: "${r.tier}"`).join(', '),
104→    );
105→  } catch (error) {
106→    assert(false, 'skf-knowledge-index.csv parsed successfully', error.message);
107→  }
108→
109→  console.log('');
110→
111→  // ============================================================
112→  // Test 2: Fragment file existence
113→  // ============================================================
114→  console.log(`${colors.yellow}Test Suite 2: Fragment Existence${colors.reset}\n`);
115→
116→  if (records.length > 0) {
117→    let missingCount = 0;
118→    for (const record of records) {
119→      const fragmentPath = path.join(kbRoot, '..', record.fragment_file);
120→      const exists = fs.existsSync(fragmentPath);
121→      if (!exists) missingCount++;
122→      assert(exists, `fragment exists: ${record.fragment_file}`);
123→    }
124→    assert(missingCount === 0, 'all fragments exist');
125→  } else {
126→    assert(false, 'fragment records loaded', 'No records found in skf-knowledge-index.csv');
127→  }
128→
129→  console.log('');
130→
131→  // ============================================================
132→  // Test 3: Tag selection logic
133→  // ============================================================
134→  console.log(`${colors.yellow}Test Suite 3: Tag Selection${colors.reset}\n`);
135→
136→  if (records.length > 0) {
137→    const firstTag = parseTags(records[0].tags)[0];
138→    const selected = records.filter((record) => parseTags(record.tags).includes(firstTag));
139→    assert(Boolean(firstTag), 'first record has at least one tag');
140→    assert(selected.length > 0, `tag filter returns results for '${firstTag}'`);
141→
142→    const none = records.filter((record) => parseTags(record.tags).includes('__no_such_tag__'));
143→    assert(none.length === 0, 'unknown tag returns no results');
144→  } else {
145→    assert(false, 'tag selection tested', 'No records to test');
146→  }
147→
148→  console.log('');
149→
150→  // ============================================================
151→  // Test 4: Cross-fragment references
152→  // ============================================================
153→  console.log(`${colors.yellow}Test Suite 4: Cross-Fragment Links${colors.reset}\n`);
154→
155→  const knowledgeDir = kbRoot;
156→  const mdFiles = fs.readdirSync(knowledgeDir).filter((name) => name.endsWith('.md'));
157→
158→  let linkCount = 0;
159→  let brokenLinks = 0;
160→
161→  for (const fileName of mdFiles) {
162→    const filePath = path.join(knowledgeDir, fileName);
163→    const content = fs.readFileSync(filePath, 'utf8');
164→
165→    const linkMatches = content.matchAll(/\]\(([^)]+)\)/g);
166→    for (const match of linkMatches) {
167→      const href = match[1].trim();
168→      if (!href.endsWith('.md') || isExternalLink(href)) continue;
169→
170→      const resolved = resolveFragmentLink(path.join(projectRoot, 'src'), href);
171→      if (!resolved) continue;
172→
173→      linkCount++;
174→      const exists = fs.existsSync(resolved);
175→      if (!exists) brokenLinks++;
176→      assert(exists, `link resolves: ${fileName} -> ${href}`);
177→    }
178→  }
179→
180→  if (linkCount === 0) {
181→    warn('no cross-fragment links detected (informational)');
182→  } else {
183→    assert(linkCount > 0, 'cross-fragment links detected (at least one)');
184→  }
185→  assert(brokenLinks === 0, 'no broken cross-fragment links');
186→
187→  console.log('');
188→
189→  // ============================================================
190→  // Summary
191→  // ============================================================
192→  console.log(`${colors.cyan}========================================`);
193→  console.log('Test Results:');
194→  console.log(`  Passed: ${colors.green}${passed}${colors.reset}`);
195→  console.log(`  Warnings: ${colors.yellow}${warned}${colors.reset}`);
196→  console.log(`  Failed: ${colors.red}${failed}${colors.reset}`);
197→  console.log(`========================================${colors.reset}\n`);
198→
199→  if (failed === 0) {
200→    console.log(`${colors.green}✨ Knowledge base tests passed!${colors.reset}\n`);
201→    process.exit(0);
202→  } else {
203→    console.log(`${colors.red}❌ Knowledge base tests failed${colors.reset}\n`);
204→    process.exit(1);
205→  }
206→}
207→
208→runTests();
209→

  1→/**
  2→ * CLI Integration Tests - Install/Update/Uninstall Flows
  3→ *
  4→ * End-to-end tests using temp directories to verify:
  5→ * - Fresh install creates all expected files
  6→ * - Update preserves config.yaml and replaces SKF files
  7→ * - Uninstall removes all tracked files
  8→ * - IDE command generation for each target
  9→ * - Manifest accuracy
 10→ *
 11→ * Usage: node test/test-cli-integration.js
 12→ */
 13→
 14→const path = require('node:path');
 15→const os = require('node:os');
 16→const fs = require('fs-extra');
 17→const yaml = require('js-yaml');
 18→
 19→// ANSI colors
 20→const colors = {
 21→  reset: '\u001B[0m',
 22→  green: '\u001B[32m',
 23→  red: '\u001B[31m',
 24→  yellow: '\u001B[33m',
 25→  cyan: '\u001B[36m',
 26→  dim: '\u001B[2m',
 27→};
 28→
 29→let passed = 0;
 30→let failed = 0;
 31→
 32→function assert(condition, testName, errorMessage = '') {
 33→  if (condition) {
 34→    console.log(`${colors.green}✓${colors.reset} ${testName}`);
 35→    passed++;
 36→  } else {
 37→    console.log(`${colors.red}✗${colors.reset} ${testName}`);
 38→    if (errorMessage) {
 39→      console.log(`  ${colors.dim}${errorMessage}${colors.reset}`);
 40→    }
 41→    failed++;
 42→  }
 43→}
 44→
 45→/**
 46→ * Create a temp directory for a test case.
 47→ */
 48→async function makeTempDir(label) {
 49→  const dir = path.join(os.tmpdir(), `skf-test-${label}-${Date.now()}`);
 50→  await fs.ensureDir(dir);
 51→  return dir;
 52→}
 53→
 54→/**
 55→ * Suppress ora spinners, console.log, and stderr writes during install to keep test output clean.
 56→ */
 57→function suppressConsole() {
 58→  const origLog = console.log;
 59→  const origStdoutWrite = process.stdout.write;
 60→  const origStderrWrite = process.stderr.write;
 61→  console.log = () => {};
 62→  process.stdout.write = () => true;
 63→  process.stderr.write = () => true;
 64→  return () => {
 65→    console.log = origLog;
 66→    process.stdout.write = origStdoutWrite;
 67→    process.stderr.write = origStderrWrite;
 68→  };
 69→}
 70→
 71→// ============================================================
 72→// Test Suites
 73→// ============================================================
 74→
 75→async function testFreshInstall() {
 76→  console.log(`${colors.yellow}Test Suite 1: Fresh Install${colors.reset}\n`);
 77→
 78→  const projectDir = await makeTempDir('fresh');
 79→
 80→  try {
 81→    const { Installer } = require('../tools/cli/lib/installer');
 82→    const installer = new Installer();
 83→
 84→    const config = {
 85→      projectDir,
 86→      skfFolder: '_bmad/skf',
 87→      project_name: 'test-project',
 88→      skills_output_folder: 'skills',
 89→      forge_data_folder: 'forge-data',
 90→      ides: ['claude-code'],
 91→      install_learning: true,
 92→      _action: 'fresh',
 93→    };
 94→
 95→    const restore = suppressConsole();
 96→    const result = await installer.install(config);
 97→    restore();
 98→
 99→    assert(result.success === true, 'install returns success');
100→
101→    // Verify SKF directory structure
102→    const skfDir = path.join(projectDir, '_bmad/skf');
103→    assert(await fs.pathExists(skfDir), 'SKF directory created');
104→    assert(await fs.pathExists(path.join(skfDir, 'agents')), 'agents/ directory created');
105→    assert(await fs.pathExists(path.join(skfDir, 'knowledge')), 'knowledge/ directory created');
106→    assert(await fs.pathExists(path.join(skfDir, 'workflows')), 'workflows/ directory created');
107→
108→    // Verify config.yaml
109→    const configPath = path.join(skfDir, 'config.yaml');
110→    assert(await fs.pathExists(configPath), 'config.yaml created');
111→    const configContent = yaml.load(await fs.readFile(configPath, 'utf8'));
112→    assert(configContent.project_name === 'test-project', 'config.yaml has correct project_name');
113→    assert(configContent.skills_output_folder === 'skills', 'config.yaml has correct skills_output_folder');
114→    assert(Array.isArray(configContent.ides) && configContent.ides.includes('claude-code'), 'config.yaml has IDEs');
115→
116→    // Verify compiled agents
117→    const agentFiles = (await fs.readdir(path.join(skfDir, 'agents'))).filter((f) => f.endsWith('.md'));
118→    assert(agentFiles.length > 0, `compiled agent .md files exist (found ${agentFiles.length})`);
119→
120→    // Verify sidecar
121→    const sidecarDir = path.join(projectDir, '_bmad/_memory/forger-sidecar');
122→    assert(await fs.pathExists(sidecarDir), 'sidecar directory created');
123→
124→    // Verify output folders
125→    assert(await fs.pathExists(path.join(projectDir, 'skills')), 'skills/ output folder created');
126→    assert(await fs.pathExists(path.join(projectDir, 'forge-data')), 'forge-data/ output folder created');
127→    assert(await fs.pathExists(path.join(projectDir, 'skills/.gitkeep')), 'skills/.gitkeep created');
128→    assert(await fs.pathExists(path.join(projectDir, 'forge-data/.gitkeep')), 'forge-data/.gitkeep created');
129→
130→    // Verify learning material
131→    assert(await fs.pathExists(path.join(projectDir, '_skf-learn')), '_skf-learn/ directory created');
132→
133→    // Verify manifest
134→    const manifestPath = path.join(projectDir, '_bmad/_config/skf-manifest.yaml');
135→    assert(await fs.pathExists(manifestPath), 'manifest created');
136→    const manifest = yaml.load(await fs.readFile(manifestPath, 'utf8'));
137→    assert(manifest.module === 'skf', 'manifest has module: skf');
138→    assert(manifest.action === 'fresh', 'manifest has action: fresh');
139→    assert(Array.isArray(manifest.files.skf) && manifest.files.skf.length > 0, 'manifest tracks SKF files');
140→    assert(Array.isArray(manifest.files.sidecar) && manifest.files.sidecar.length > 0, 'manifest tracks sidecar files');
141→
142→    // Verify IDE commands
143→    const claudeCommandsDir = path.join(projectDir, '.claude/commands');
144→    assert(await fs.pathExists(claudeCommandsDir), '.claude/commands/ created');
145→    const commandFiles = await fs.readdir(claudeCommandsDir);
146→    const agentCmds = commandFiles.filter((f) => f.startsWith('bmad-agent-skf-'));
147→    const workflowCmds = commandFiles.filter((f) => f.startsWith('bmad-skf-'));
148→    assert(agentCmds.length > 0, `agent command files generated (found ${agentCmds.length})`);
149→    assert(workflowCmds.length > 0, `workflow command files generated (found ${workflowCmds.length})`);
150→
151→    // Verify manifest tracks IDE files
152→    assert(Array.isArray(manifest.files.ide_commands) && manifest.files.ide_commands.length > 0, 'manifest tracks IDE command files');
153→  } catch (error) {
154→    assert(false, 'fresh install completes without error', error.message);
155→  } finally {
156→    await fs.remove(projectDir);
157→  }
158→
159→  console.log('');
160→}
161→
162→async function testUpdatePreservesConfig() {
163→  console.log(`${colors.yellow}Test Suite 2: Update Preserves Config${colors.reset}\n`);
164→
165→  const projectDir = await makeTempDir('update');
166→
167→  try {
168→    const { Installer } = require('../tools/cli/lib/installer');
169→    const installer = new Installer();
170→
171→    // Step 1: Fresh install
172→    const config = {
173→      projectDir,
174→      skfFolder: '_bmad/skf',
175→      project_name: 'original-name',
176→      skills_output_folder: 'skills',
177→      forge_data_folder: 'forge-data',
178→      ides: ['cursor'],
179→      install_learning: false,
180→      _action: 'fresh',
181→    };
182→
183→    let restore = suppressConsole();
184→    await installer.install(config);
185→    restore();
186→
187→    // Verify initial config
188→    const skfDir = path.join(projectDir, '_bmad/skf');
189→    const configPath = path.join(skfDir, 'config.yaml');
190→    const origConfig = await fs.readFile(configPath, 'utf8');
191→    assert(origConfig.includes('original-name'), 'initial config has original project name');
192→
193→    // Add a marker file to sidecar to verify it persists
194→    const sidecarMarker = path.join(projectDir, '_bmad/_memory/forger-sidecar/user-state.yaml');
195→    await fs.writeFile(sidecarMarker, 'custom: state\n', 'utf8');
196→
197→    // Step 2: Update
198→    const updateConfig = {
199→      projectDir,
200→      skfFolder: '_bmad/skf',
201→      _action: 'update',
202→    };
203→
204→    restore = suppressConsole();
205→    const result = await installer.install(updateConfig);
206→    restore();
207→
208→    assert(result.success === true, 'update returns success');
209→
210→    // Config should be preserved
211→    const updatedConfig = await fs.readFile(configPath, 'utf8');
212→    assert(updatedConfig.includes('original-name'), 'config.yaml preserved after update');
213→
214→    // SKF files should still exist
215→    assert(await fs.pathExists(path.join(skfDir, 'agents')), 'agents/ exists after update');
216→    assert(await fs.pathExists(path.join(skfDir, 'workflows')), 'workflows/ exists after update');
217→
218→    // Sidecar user state should persist (sidecar files are not overwritten)
219→    assert(await fs.pathExists(sidecarMarker), 'sidecar user state preserved after update');
220→
221→    // Manifest should reflect update action
222→    const manifestPath = path.join(projectDir, '_bmad/_config/skf-manifest.yaml');
223→    const manifest = yaml.load(await fs.readFile(manifestPath, 'utf8'));
224→    assert(manifest.action === 'update', 'manifest action is update');
225→  } catch (error) {
226→    assert(false, 'update flow completes without error', error.message);
227→  } finally {
228→    await fs.remove(projectDir);
229→  }
230→
231→  console.log('');
232→}
