234→async function testUninstallCleansUp() {
235→  console.log(`${colors.yellow}Test Suite 3: Uninstall Cleanup${colors.reset}\n`);
236→
237→  const projectDir = await makeTempDir('uninstall');
238→
239→  try {
240→    const { Installer } = require('../tools/cli/lib/installer');
241→    const { readManifest, MANIFEST_DIR, MANIFEST_FILE } = require('../tools/cli/lib/manifest');
242→    const installer = new Installer();
243→
244→    // Install first
245→    const config = {
246→      projectDir,
247→      skfFolder: '_bmad/skf',
248→      project_name: 'uninstall-test',
249→      skills_output_folder: 'skills',
250→      forge_data_folder: 'forge-data',
251→      ides: ['claude-code', 'cursor'],
252→      install_learning: true,
253→      _action: 'fresh',
254→    };
255→
256→    let restore = suppressConsole();
257→    await installer.install(config);
258→    restore();
259→
260→    // Verify files exist before uninstall
261→    assert(await fs.pathExists(path.join(projectDir, '_bmad/skf')), 'SKF dir exists before uninstall');
262→    assert(await fs.pathExists(path.join(projectDir, '_skf-learn')), '_skf-learn exists before uninstall');
263→    assert(await fs.pathExists(path.join(projectDir, '.claude/commands')), '.claude/commands exists before uninstall');
264→    assert(await fs.pathExists(path.join(projectDir, '.cursor/commands')), '.cursor/commands exists before uninstall');
265→
266→    // Read manifest
267→    const manifest = await readManifest(projectDir);
268→    assert(manifest !== null, 'manifest exists before uninstall');
269→
270→    // Simulate uninstall: remove all tracked files (mirrors uninstall.js logic without interactive prompt)
271→    restore = suppressConsole();
272→
273→    // Remove IDE commands
274→    for (const file of manifest.files.ide_commands || []) {
275→      const fullPath = path.join(projectDir, file);
276→      if (await fs.pathExists(fullPath)) await fs.remove(fullPath);
277→    }
278→    // Clean empty IDE dirs
279→    const cleanedDirs = new Set();
280→    for (const f of manifest.files.ide_commands || []) {
281→      const dir = path.dirname(f);
282→      if (!cleanedDirs.has(dir)) {
283→        cleanedDirs.add(dir);
284→        const dirPath = path.join(projectDir, dir);
285→        if (await fs.pathExists(dirPath)) {
286→          const entries = await fs.readdir(dirPath);
287→          if (entries.length === 0) {
288→            await fs.remove(dirPath);
289→            const parentDir = path.join(projectDir, path.dirname(dir));
290→            if (await fs.pathExists(parentDir)) {
291→              const parentEntries = await fs.readdir(parentDir);
292→              if (parentEntries.length === 0) await fs.remove(parentDir);
293→            }
294→          }
295→        }
296→      }
297→    }
298→
299→    // Remove learning
300→    const learnDir = path.join(projectDir, '_skf-learn');
301→    if (await fs.pathExists(learnDir)) await fs.remove(learnDir);
302→
303→    // Remove output scaffolding
304→    for (const file of manifest.files.output || []) {
305→      const fullPath = path.join(projectDir, file);
306→      if (await fs.pathExists(fullPath)) await fs.remove(fullPath);
307→    }
308→    for (const folder of [manifest.skills_output_folder, manifest.forge_data_folder]) {
309→      if (folder) {
310→        const dirPath = path.join(projectDir, folder);
311→        if (await fs.pathExists(dirPath)) {
312→          const entries = await fs.readdir(dirPath);
313→          if (entries.length === 0) await fs.remove(dirPath);
314→        }
315→      }
316→    }
317→
318→    // Remove sidecar
319→    const sidecarDir = path.join(projectDir, '_bmad/_memory/forger-sidecar');
320→    if (await fs.pathExists(sidecarDir)) await fs.remove(sidecarDir);
321→    const memoryDir = path.join(projectDir, '_bmad/_memory');
322→    if (await fs.pathExists(memoryDir)) {
323→      const entries = await fs.readdir(memoryDir);
324→      if (entries.length === 0) await fs.remove(memoryDir);
325→    }
326→
327→    // Remove SKF module
328→    const skfDir = path.join(projectDir, manifest.skf_folder);
329→    if (await fs.pathExists(skfDir)) await fs.remove(skfDir);
330→
331→    // Remove manifest
332→    const manifestPath = path.join(projectDir, MANIFEST_DIR, MANIFEST_FILE);
333→    if (await fs.pathExists(manifestPath)) await fs.remove(manifestPath);
334→    const configDir = path.join(projectDir, MANIFEST_DIR);
335→    if (await fs.pathExists(configDir)) {
336→      const entries = await fs.readdir(configDir);
337→      if (entries.length === 0) await fs.remove(configDir);
338→    }
339→    const bmadDir = path.join(projectDir, '_bmad');
340→    if (await fs.pathExists(bmadDir)) {
341→      const entries = await fs.readdir(bmadDir);
342→      if (entries.length === 0) await fs.remove(bmadDir);
343→    }
344→
345→    restore();
346→
347→    // Verify everything is cleaned up
348→    assert(!(await fs.pathExists(path.join(projectDir, '_bmad/skf'))), 'SKF dir removed');
349→    assert(!(await fs.pathExists(path.join(projectDir, '_skf-learn'))), '_skf-learn removed');
350→    assert(!(await fs.pathExists(path.join(projectDir, '.claude/commands'))), '.claude/commands removed');
351→    assert(!(await fs.pathExists(path.join(projectDir, '.cursor/commands'))), '.cursor/commands removed');
352→    assert(!(await fs.pathExists(path.join(projectDir, 'skills'))), 'skills/ output folder removed');
353→    assert(!(await fs.pathExists(path.join(projectDir, 'forge-data'))), 'forge-data/ output folder removed');
354→    assert(!(await fs.pathExists(path.join(projectDir, '_bmad'))), '_bmad/ cleaned up (empty)');
355→  } catch (error) {
356→    assert(false, 'uninstall flow completes without error', error.message);
357→  } finally {
358→    await fs.remove(projectDir);
359→  }
360→
361→  console.log('');
362→}
